clock c;

double_t totalRate = INFINITE_TIME_DOUBLE, oldRate = INFINITE_TIME_DOUBLE;

double_t compute_rate() {
	double_t R12_R16_r = scenario1(k_R12_R16, int_to_double(R12), int_to_double(R12Levels), true);
	double_t R0_R16_r = scenario1(k_R0_R16, int_to_double(R0), int_to_double(R0Levels), true);
	R12_R16.T = _ANIMO_round(inverse(R12_R16_r));
	R0_R16.T = _ANIMO_round(inverse(R0_R16_r));
	return subtract(add(zero, R12_R16_r), R0_R16_r);
}

void update() {
	oldRate = totalRate;
	totalRate = compute_rate();
	if(totalRate.b < 0) {
		delta = -1;
		totalRate.b = -totalRate.b;
	} 
	else {
		delta = 1;
	}
	if(totalRate.b != 0) {
		TL = _ANIMO_round(inverse(totalRate));
		TU = TL;
		if(TL < 1) {
			TL = 1;
		} 
		if(TU < 1) {
			TU = 1;
		} 
	} 
	else {
		TL = INFINITE_TIME;
		TU = INFINITE_TIME;
	}
	if(TL != INFINITE_TIME and TL > TU) {
		TL = TU;
	} 
}

void react() {
	if(0 <= R+delta and R+delta <= MAX) {
		R = R+delta;
	} 
}

void make_urgent() {
	c = 0;
	TU = 0;
	TL = 0;
}

bool rate_significantly_changed(double_t oldRate, double_t newRate) {
	if((oldRate.b < 0 and newRate.b > 0 or oldRate.b > 0 and newRate.b < 0) and R < MAX and R > 0) {
		return true;
	} 
	return false;
}

void decide_reset() {
	if(rate_significantly_changed(oldRate, totalRate)) {
		c = 0;
	} 
}

