	return minCrit == N_REACTANTS and TL != INFINITE_TIME and (delta >= 0 and R < MAX or delta < 0 and R > 0);
}

bool cant_react() {
	return minCrit == N_REACTANTS and (TL == INFINITE_TIME or delta >= 0 and R == MAX or delta < 0 and R == 0);
}

